section.codeblock:
pipeline {
    agent {
        docker { image 'ghcr.io/dita-ot/dita-ot:4.3' }
    }
    triggers {
        pollSCM('H/5 * * * *')
    }
    stages {
        stage('Install Plugins') {
            steps {
                sh 'dita --install plugins/com.extense.html5.branded'
                sh 'dita --install plugins/com.extense.pdf.branded'
            }
        }
        stage('Build') {
            steps {
                sh 'dita --project=build-project.xml -v'
            }
        }
        stage('Archive') {
            steps {
                archiveArtifacts artifacts: 'output/**/*'
            }
        }
        stage('Deploy') {
            when { branch 'main' }
            steps {
                sh 'rsync -avz output/html5/ docs-server:/var/www/docs/'
            }
        }
    }
    post {
        failure {
            mail to: 'docs-team@extense.com',
                 subject: "DITA build failed: ${env.JOB_NAME}",
                 body: "Check ${env.BUILD_URL} for details."
        }
    }
}
